/** Parser for Assignment 1 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {

  private Lexer in;

  Parser(Lexer i) {
    in = i;
  }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp). */
  public AST parse() throws ParseException {
    AST result = parseExp();
    Token t = in.readToken();
    if (t != null) {
      throw new ParseException("Expected end of input but found: " + t);
    }
    return result;
  }

  /** Parses:
    *   <exp> ::= if <exp> then <exp> else <exp>
    *           | let <def>+ in <exp>
    *           | map <id-list> to <exp>
    *           | <term> { <binop> <term> }*   (left-associatively!)
    */
  private AST parseExp() {
    Token t = in.peek();
    if (t == Lexer.IF)  return parseIf();
    if (t == Lexer.LET) return parseLet();
    if (t == Lexer.MAP) return parseMap();
    return parseBinaryExp();
  }

  /** Parses: if <exp> then <exp> else <exp> */
  private If parseIf() {
    in.readToken(); // consume 'if'
    AST test = parseExp();
    Token t = in.readToken();
    if (t != Lexer.THEN)
      throw new ParseException("Expected 'then' but found: " + t);
    AST conseq = parseExp();
    t = in.readToken();
    if (t != Lexer.ELSE)
      throw new ParseException("Expected 'else' but found: " + t);
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses: let <def>+ in <exp>
    * Def ::= Id := Exp ;
    */
  private Let parseLet() {
    in.readToken(); // consume 'let'
    List<Def> defs = new ArrayList<Def>();
    // Parse one or more Defs until we see 'in'
    Token t = in.peek();
    if (t == Lexer.IN)
      throw new ParseException("Expected at least one definition in let");
    while (in.peek() != Lexer.IN) {
      if (in.peek() == null)
        throw new ParseException("Unexpected end of input inside let");
      defs.add(parseDef());
    }
    in.readToken(); // consume 'in'
    AST body = parseExp();
    return new Let(defs.toArray(new Def[0]), body);
  }

  /** Parses: Id := Exp ; */
  private Def parseDef() {
    Token t = in.readToken();
    if (!(t instanceof Variable))
      throw new ParseException("Expected variable in definition but found: " + t);
    Variable lhs = (Variable) t;
    t = in.readToken();
    if (t != Lexer.BIND)
      throw new ParseException("Expected ':=' in definition but found: " + t);
    AST rhs = parseExp();
    t = in.readToken();
    if (t != SemiColon.ONLY)
      throw new ParseException("Expected ';' after definition but found: " + t);
    return new Def(lhs, rhs);
  }

  /** Parses: map <id-list> to <exp> */
  private Map parseMap() {
    in.readToken(); // consume 'map'
    Variable[] vars = parseIdList();
    Token t = in.readToken();
    if (t != Lexer.TO)
      throw new ParseException("Expected 'to' in map expression but found: " + t);
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses: IdList ::= { PropIdList }
    *          PropIdList ::= Id { , Id }*
    */
  private Variable[] parseIdList() {
    List<Variable> vars = new ArrayList<Variable>();
    Token t = in.peek();
    if (t instanceof Variable) {
      in.readToken();
      vars.add((Variable) t);
      while (in.peek() == Comma.ONLY) {
        in.readToken(); // consume ','
        t = in.readToken();
        if (!(t instanceof Variable))
          throw new ParseException("Expected variable after ',' in id list but found: " + t);
        vars.add((Variable) t);
      }
    }
    return vars.toArray(new Variable[0]);
  }

  /** Parses: BinaryExp ::= Term { BinOp Term }*   (left-associatively) */
  private AST parseBinaryExp() {
    AST left = parseTerm();
    while (true) {
      Token t = in.peek();
      if (!(t instanceof OpToken) || !((OpToken) t).isBinOp()) break;
      in.readToken(); // consume the BinOp token
      BinOp op = ((OpToken) t).toBinOp();
      AST right = parseTerm();
      left = new BinOpApp(op, left, right);
    }
    return left;
  }

  /** Parses:
    *   Term ::= Unop Term
    *          | Factor { ( ExpList ) }
    *          | Empty | Int | Bool
    */
  private AST parseTerm() {
    Token t = in.peek();

    // Unop Term
    if (t instanceof OpToken && ((OpToken) t).isUnOp()) {
      in.readToken(); // consume unop
      UnOp op = ((OpToken) t).toUnOp();
      AST arg = parseTerm();
      return new UnOpApp(op, arg);
    }

    // Int constant (not applicable for function application)
    if (t instanceof IntConstant) {
      in.readToken();
      return (IntConstant) t;
    }

    // Bool constant
    if (t instanceof BoolConstant) {
      in.readToken();
      return (BoolConstant) t;
    }

    // Empty constant
    if (t instanceof EmptyConstant) {
      in.readToken();
      return (EmptyConstant) t;
    }

    // Factor { ( ExpList ) }
    AST factor = parseFactor();
    if (in.peek() == LeftParen.ONLY) {
      in.readToken(); // consume '('
      AST[] args = parseExpList();
      Token close = in.readToken();
      if (close != RightParen.ONLY)
        throw new ParseException("Expected ')' in application but found: " + close);
      return new App(factor, args);
    }
    return factor;
  }

  /** Parses: Factor ::= ( Exp ) | Prim | Id */
  private AST parseFactor() {
    Token t = in.readToken();
    if (t == null)
      throw new ParseException("Unexpected end of input in expression");
    if (t == LeftParen.ONLY) {
      AST exp = parseExp();
      Token close = in.readToken();
      if (close != RightParen.ONLY)
        throw new ParseException("Expected ')' but found: " + close);
      return exp;
    }
    if (t instanceof PrimFun) return (PrimFun) t;
    if (t instanceof Variable) return (Variable) t;
    throw new ParseException("Unexpected token in expression: " + t);
  }

  /** Parses: ExpList ::= { PropExpList }
    *          PropExpList ::= Exp { , Exp }*
    */
  private AST[] parseExpList() {
    List<AST> expList = new ArrayList<AST>();
    if (in.peek() != RightParen.ONLY && in.peek() != null) {
      expList.add(parseExp());
      while (in.peek() == Comma.ONLY) {
        in.readToken(); // consume ','
        expList.add(parseExp());
      }
    }
    return expList.toArray(new AST[0]);
  }
}

